import React from 'react';
import { NativeModules } from 'react-native';

// Custom logger class
class CustomLogger {
  static log(message) {
    console.log(`[DEBUG] ${message}`);
    NativeModules.LoggerModule.log(message);
  }

  static debug(message) {
    console.debug(`[DEBUG] ${message}`);
    NativeModules.LoggerModule.debug(message);
  }
}

// AsyncStorage hook for logging operations
const useLogAsyncStorage = () => {
  const AsyncStorage = React.useContext(NativeModules.AsyncStorage);

  const logAsyncStorageOperation = async (operation, data) => {
    CustomLogger.log(`AsyncStorage: ${operation} with data:`, data);
    try {
      await AsyncStorage[operation](data);
      CustomLogger.log(`AsyncStorage: Successfully performed ${operation}`);
    } catch (error) {
      CustomLogger.error(`AsyncStorage: Error performing ${operation}`, error);
    }
  };

  return [logAsyncStorageOperation];
};

// Network requests hook for logging
const useLogNetworkRequests = () => {
  const AxiosInstance = React.useContext(NativeModules.NetworkRequests);

  const logNetworkRequest = async (url, method, data) => {
    CustomLogger.log(`Network Request: ${method} to ${url} with data:`, data);
    try {
      await AxiosInstance.request({ url, method, data });
      CustomLogger.log('Network Request: Successfully sent request');
    } catch (error) {
      CustomLogger.error('Network Request: Error sending request', error);
    }
  };

  return [logNetworkRequest];
};

// Global event listener for user actions and state changes
React.useEffect(() => {
  const handleEvent = (event) => {
    if (event.nativeEvent.action === 'AppStateChange') {
      CustomLogger.log(`App State Changed: ${event.nativeEvent.appState}`);
    } else if (event.nativeEvent.action === 'BackgroundTimeRefresh') {
      CustomLogger.log('Background Time Refreshed');
    }
  };

  const unsubscribe = NativeModules.AppEvents.addListener('appState', handleEvent);
  return unsubscribe;
}, []);

// Example usage
const App = () => {
  const [logAsyncStorageOperation] = useLogAsyncStorage();
  const [logNetworkRequest] = useLogNetworkRequests();

  const login = async (username, password) => {
    try {
      const response = await fetch('https://example.com/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const token = await response.json();
      logNetworkRequest('https://example.com/api/endpoint', 'GET');
      AsyncStorage.setItem('token', token);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      <Button title="Login" onPress={() => login('username', 'password')} />
      <Text>AsyncStorage: {AsyncStorage.getItem('key')}</Text>
    </View>
  );
};

export default App;